#include <stdio.h>
#include <stdint.h>

#define HEADER_NAME "INT_TO_STRING"
#define MAX_VALUE UINT16_MAX

int
main(int    argc,
     char **argv)
{
	uint16_t i;
	FILE *f = NULL;

	if (argc < 2) {
		printf("Please provide a filepath\n");
		return 1;
	}

	f = fopen(argv[1], "w");
	if (f == NULL) {
		printf("Couldn't open filepath\n");
		return 1;
	}

	fprintf(f,
	        "/* This file is automatically generated. Do NOT change it.\n"
	        " */\n"
	        "\n"
	        "#ifndef _" HEADER_NAME "_H\n"
	        "#define _" HEADER_NAME "_H\n"
	        "\n"
	        "static const char *NUMBERSTRING[] = {\n");

	i = 0;
	while (1) {
		fprintf(f, "\t\"%i\",\n", i);

		if (i >= MAX_VALUE) {
		break;
		}
	i++;
	}

	fprintf(f,
	        "};\n"
	        "\n"
	        "#endif /* _" HEADER_NAME "_H */\n");

	fclose(f);

	return 0;
}
